import { Injectable } from '@angular/core';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { AssetAllocationForm, AssetReturnForm } from '../../models/forms.model';

@Injectable({
  providedIn: 'root'
})
export class PdfGeneratorService {

  constructor() {}

  /**
   * Generates a stylized CDS logo in base64
   */
  private getLogoBase64(): string {
    return 'data:image/png;base64,';
  }

  /**
   * Generates a PDF document for Asset Allocation or Asset Return
   * @param type Form type: 'allocation' or 'return'
   * @param data Form data matching the structures
   */
  generatePdf(type: 'allocation' | 'return', data: AssetAllocationForm | AssetReturnForm): { doc: jsPDF, blobUrl: string, fileName: string } {
    const doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4'
    });

    const isAllocation = type === 'allocation';
    
    // Format Employee Name for filename (replace spaces with underscores)
    const empName = (data.employeeInfo.employeeName || 'Employee').trim().replace(/\s+/g, '_');
    
    // Get Date formatted as ddmmyyyy (no hyphens/slashes)
    let ddmmyyyy = '';
    if (data.employeeInfo.date) {
      const parts = data.employeeInfo.date.split('-');
      if (parts.length === 3) {
        // If yyyy-mm-dd (default HTML date output)
        if (parts[0].length === 4) {
          ddmmyyyy = `${parts[2]}${parts[1]}${parts[0]}`;
        } else {
          ddmmyyyy = `${parts[0]}${parts[1]}${parts[2]}`;
        }
      } else {
        const cleanDate = new Date(data.employeeInfo.date);
        const dd = String(cleanDate.getDate()).padStart(2, '0');
        const mm = String(cleanDate.getMonth() + 1).padStart(2, '0');
        const yyyy = cleanDate.getFullYear();
        ddmmyyyy = `${dd}${mm}${yyyy}`;
      }
    } else {
      const today = new Date();
      const dd = String(today.getDate()).padStart(2, '0');
      const mm = String(today.getMonth() + 1).padStart(2, '0');
      const yyyy = today.getFullYear();
      ddmmyyyy = `${dd}${mm}${yyyy}`;
    }

    const prefix = isAllocation ? 'AAF' : 'ARF';
    const fileName = `${prefix}_${empName}_${ddmmyyyy}.pdf`;

    // --- 1. HEADER SECTION ---
    // Add CDS Logo (top-left)
    const logoBase64 = this.getLogoBase64();
    doc.addImage(logoBase64, 'PNG', 15, 8, 30, 15);

    // Titles (centered for both AAF and ARF to match user return form style)
    doc.setTextColor(30, 58, 138); // Deep Blue #1e3a8a
    
    doc.setFont('Helvetica', 'bold');
    doc.setFontSize(15);
    const titleText = isAllocation ? 'ASSET ALLOCATION FORM' : 'ASSET RETURN FORM';
    doc.text(titleText, 105, 17, { align: 'center' });
    
    // Subtitle
    doc.setFontSize(9.5);
    doc.text('CARIDIGISYSTEMS PRIVATE LIMITED', 105, 22, { align: 'center' });

    let currentY = 36;

    // --- 2. EMPLOYEE INFORMATION SECTION ---
    doc.setTextColor(30, 58, 138); // Deep Blue
    doc.setFont('Helvetica', 'bold');
    doc.setFontSize(11);
    const section1Title = isAllocation ? 'EMPLOYEE INFORMATION' : 'RETURN INFORMATION';
    doc.text(section1Title, 15, currentY);

    // Date (Placed on the same line as the Section Title for both forms, formatted as dd/mm/yyyy)
    doc.text(`Date: ${this.formatDate(data.employeeInfo.date || '')}`, 210 - 15, currentY, { align: 'right' });

    currentY += 4;

    const empData = data.employeeInfo;

    if (isAllocation) {
      // AAF: 2-column vertical table layout with exact widths (78mm label, 102mm value)
      autoTable(doc, {
        startY: currentY,
        margin: { left: 15, right: 15 },
        theme: 'grid',
        styles: {
          fontSize: 9,
          cellPadding: 2.5,
          textColor: [30, 41, 59], // slate-800
          font: 'Helvetica',
          lineColor: [148, 163, 184], // slate-400
          lineWidth: 0.15
        },
        columnStyles: {
          0: { fontStyle: 'bold', cellWidth: 78, fillColor: [238, 242, 246] }, // Light blue-gray background for label
          1: { cellWidth: 102, fillColor: [255, 255, 255] } // White for value
        },
        body: [
          ['Employee Name', empData.employeeName],
          ['Employee ID', empData.employeeId],
          ['Department', empData.department],
          ['Designation', empData.designation],
          ['Location', empData.location],
          ['Date of Joining', empData.dateOfJoining || ''],
          ['Email ID', empData.emailId],
          ['Contact Number', empData.contactNumber]
        ]
      });
    } else {
      // ARF: 4-column grid layout with exact widths (40mm label, 50mm value)
      autoTable(doc, {
        startY: currentY,
        margin: { left: 15, right: 15 },
        theme: 'grid',
        styles: {
          fontSize: 9,
          cellPadding: 2.5,
          textColor: [30, 41, 59],
          font: 'Helvetica',
          lineColor: [148, 163, 184],
          lineWidth: 0.15
        },
        columnStyles: {
          0: { fontStyle: 'bold', cellWidth: 40, fillColor: [238, 242, 246] },
          1: { cellWidth: 50, fillColor: [255, 255, 255] },
          2: { fontStyle: 'bold', cellWidth: 40, fillColor: [238, 242, 246] },
          3: { cellWidth: 50, fillColor: [255, 255, 255] }
        },
        body: [
          ['Employee Name', empData.employeeName, 'Employee ID', empData.employeeId],
          ['Department', empData.department, 'Designation', empData.designation],
          ['Location', empData.location, 'Last Working Day', empData.lastWorkingDay || ''],
          ['Email ID', empData.emailId, 'Contact Number', empData.contactNumber]
        ]
      });
    }

    currentY = (doc as any).lastAutoTable.finalY + 8;

    // --- 3. ASSETS DETAILS SECTION ---
    doc.setTextColor(30, 58, 138); // Deep Blue
    doc.setFont('Helvetica', 'bold');
    doc.setFontSize(11);
    const section2Title = isAllocation ? 'ASSET DETAILS' : 'ASSETS BEING RETURNED';
    doc.text(section2Title, 15, currentY);
    currentY += 4;

    // Build Table headers and rows
    const tableHeaders = isAllocation 
      ? [['S.No', 'Asset Type', 'Asset Tag', 'Serial Number', 'Brand / Model', 'Condition']]
      : [['S.No', 'Asset Type', 'Asset Tag', 'Serial Number', 'Brand / Model', 'Returned Condition', 'Remarks']];

    const tableRows = data.assets.map((asset, idx) => {
      if (isAllocation) {
        return [
          (idx + 1).toString(),
          asset.assetType || '',
          asset.assetTag || '',
          asset.serialNumber || '',
          asset.brandModel || '',
          asset.condition || ''
        ];
      } else {
        return [
          (idx + 1).toString(),
          asset.assetType || '',
          asset.assetTag || '',
          asset.serialNumber || '',
          asset.brandModel || '',
          asset.returnedCondition || '',
          asset.remarks || ''
        ];
      }
    });

    // Pad empty rows up to 5 so it matches the image layout look!
    while (tableRows.length < 5) {
      const emptyIdx = tableRows.length + 1;
      if (isAllocation) {
        tableRows.push([emptyIdx.toString(), '', '', '', '', '']);
      } else {
        tableRows.push([emptyIdx.toString(), '', '', '', '', '', '']);
      }
    }

    // Explicit column styles for Asset tables to match column alignments
    const assetColumnStyles = isAllocation 
      ? {
          0: { cellWidth: 12, fontStyle: 'bold', halign: 'center' }, // S.No
          1: { cellWidth: 33 }, // Asset Type
          2: { cellWidth: 33 }, // Asset Tag
          3: { cellWidth: 33 }, // Serial Number
          4: { cellWidth: 39 }, // Brand / Model
          5: { cellWidth: 30 }  // Condition
        }
      : {
          0: { cellWidth: 12, fontStyle: 'bold', halign: 'center' }, // S.No
          1: { cellWidth: 20 }, // Asset Type
          2: { cellWidth: 30 }, // Asset Tag
          3: { cellWidth: 30 }, // Serial Number
          4: { cellWidth: 35 }, // Brand / Model
          5: { cellWidth: 28 }, // Returned Condition
          6: { cellWidth: 25 }  // Remarks
        };

    autoTable(doc, {
      startY: currentY,
      margin: { left: 15, right: 15 },
      head: tableHeaders,
      body: tableRows,
      theme: 'grid',
      styles: {
        fontSize: 8.5,
        cellPadding: 2.2,
        valign: 'middle',
        font: 'Helvetica',
        lineColor: [148, 163, 184],
        lineWidth: 0.15,
        textColor: [30, 41, 59]
      },
      headStyles: {
        fillColor: [219, 234, 254], // Light blue-gray #dbeafe
        textColor: [30, 41, 59],
        fontStyle: 'bold'
      },
      columnStyles: assetColumnStyles as any,
      alternateRowStyles: {
        fillColor: [255, 255, 255]
      }
    });

    currentY = (doc as any).lastAutoTable.finalY + 8;

    // Check if we need to add a new page (A4 height is 297mm. If currentY is > 218, let's push the rest to Page 2)
    if (currentY > 218) {
      doc.addPage();
      currentY = 20;
    }

    // --- 4. DECLARATION SECTION ---
    doc.setTextColor(30, 58, 138); // Deep Blue
    doc.setFont('Helvetica', 'bold');
    doc.setFontSize(11);
    doc.text('DECLARATION', 15, currentY);
    currentY += 5;

    const declarationText = isAllocation
      ? 'I acknowledge receipt of the above-mentioned assets and agree to use and return them in good working condition upon request or separation from the company.'
      : 'I hereby confirm that I have returned the above-mentioned company assets to the IT/Admin department.';

    doc.setTextColor(15, 23, 42); // slate-900
    doc.setFont('Helvetica', 'normal');
    doc.setFontSize(9.5);
    
    // Split text to fit inside the margins
    const textLines = doc.splitTextToSize(declarationText, 210 - 30);
    doc.text(textLines, 15, currentY);

    currentY += textLines.length * 5 + 6;

    // Check height for signatures
    if (currentY > 225) {
      doc.addPage();
      currentY = 20;
    }

    // --- 5. SIGNATURES & ACKNOWLEDGEMENT TABLE ---
    const adminLabel = isAllocation ? 'IT Admin' : 'IT/Admin';
    const employeeNameVal = data.signatures.employeeNameText || empData.employeeName || '';
    const adminNameVal = data.signatures.itAdminNameText || '';

    autoTable(doc, {
      startY: currentY,
      margin: { left: 15, right: 15 },
      theme: 'grid',
      styles: {
        fontSize: 9.5,
        cellPadding: 3,
        textColor: [30, 41, 59],
        font: 'Helvetica',
        lineColor: [148, 163, 184],
        lineWidth: 0.15
      },
      columnStyles: {
        0: { cellWidth: 90 },
        1: { cellWidth: 90 }
      },
      body: [
        [`Employee Name : ${employeeNameVal}`, `${adminLabel} Name : ${adminNameVal}`],
        // Row 2 is tall to host signature image and signature label
        ['\n\n\nEmployee Signature : \n', `\n\n\n${adminLabel} Signature : \n`],
        [`Date : ${this.formatDate(empData.date)}`, `Date : ${this.formatDate(empData.date)}`]
      ],
      didDrawCell: (cellData) => {
        // Embed signature images in row 2 (which is index 1 of the body)
        if (cellData.row.index === 1 && cellData.section === 'body') {
          const signatureImg = cellData.column.index === 0 
            ? data.signatures.employeeSignature 
            : data.signatures.itAdminSignature;
          
          if (signatureImg) {
            // Draw signature image centered in the upper half of the cell
            const x = cellData.cell.x + 22;
            const y = cellData.cell.y + 2;
            const width = 45;
            const height = 13;
            try {
              doc.addImage(signatureImg, 'PNG', x, y, width, height);
            } catch (e) {
              console.error('Error adding signature to PDF cell', e);
            }
          }
        }
      }
    });

    // --- 6. FOOTER (confidentiality, page numbers) ---
    const totalPages = (doc as any).internal.getNumberOfPages();
    for (let i = 1; i <= totalPages; i++) {
      doc.setPage(i);
      
      // Footer line
      doc.setDrawColor(241, 245, 249); // slate-100
      doc.line(15, 285, 210 - 15, 285);
      
      doc.setFont('Helvetica', 'normal');
      doc.setFontSize(7.5);
      doc.setTextColor(148, 163, 184); // slate-400
      doc.text('Confidential - CDS Internal Use Only', 15, 289);
      doc.text(`Generated on ${new Date().toLocaleDateString()}`, 105, 289, { align: 'center' });
      doc.text(`Page ${i} of ${totalPages}`, 210 - 15, 289, { align: 'right' });
    }

    // Generate blob URL for browser preview
    const pdfBlob = doc.output('blob');
    const blobUrl = URL.createObjectURL(pdfBlob);

    return {
      doc,
      blobUrl,
      fileName
    };
  }

  private formatDate(dateStr: string): string {
    if (!dateStr) return '';
    if (dateStr.includes('-')) {
      const parts = dateStr.split('-');
      if (parts[0].length === 4) {
        // yyyy-mm-dd -> dd/mm/yyyy
        return `${parts[2]}/${parts[1]}/${parts[0]}`;
      }
      return parts.join('/');
    }
    return dateStr;
  }
}
